import re, pathlib
f = pathlib.Path('/Users/gbang/Downloads/algora/workspace/7c1e38e4-5b67-41cf-b0ba-3d95865f88f3_hld/_response.md')
text = f.read_text()
blocks = re.findall(r'```mermaid\n(.*?)```', text, re.S)
print(f"mermaid blocks: {len(blocks)}")
# breaking chars to check INSIDE labels (we check inside [], |...|, edge text)
bad = set('():;/"<>{}')
for i, b in enumerate(blocks, 1):
    lines = b.splitlines()
    issues = []
    for ln in lines:
        # node labels [..] and ((..)) and [(..)] and [[..]]
        for lab in re.findall(r'\[+\(?(.*?)\)?\]+', ln):
            for ch in lab:
                if ch in bad:
                    issues.append((ln.strip(), lab, ch))
        # edge labels |"..."| or |...|
        for lab in re.findall(r'\|"?(.*?)"?\|', ln):
            for ch in lab:
                if ch in bad:
                    issues.append((ln.strip(), lab, ch))
    print(f"--- block {i}: first line: {lines[0].strip()}  nodes/lines={len(lines)}")
    if issues:
        for ln, lab, ch in issues:
            print(f"    !! BREAKING CHAR {ch!r} in label {lab!r}  line: {ln}")
    else:
        print("    OK - no breaking chars in labels")
